{
  "name": "small-ts-lib",
  "version": "0.1.0",
  "description": "A tiny TypeScript library with one function and a unit test (TypeScript + Jest)",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "scripts": {
    "build": "tsc -p tsconfig.json",
    "test": "jest --colors",
    "start": "node dist/index.js"
  },
  "license": "MIT",
  "devDependencies": {
    "@types/jest": "^29.5.0",
    "jest": "^29.6.0",
    "ts-jest": "^29.1.0",
    "typescript": "^5.1.0"
  }
}

/**
 * A tiny example function for the library.
 * Keeps the project runnable and testable.
 */

export function add(a: number, b: number): number {
  return a + b;
}

// a tiny default export (optional)
export default { add };

import { add } from '../src/index';

describe('add()', () => {
  test('adds two positive numbers', () => {
    expect(add(1, 2)).toBe(3);
  });

  test('adds negative and positive number', () => {
    expect(add(-1, 4)).toBe(3);
  });
});
